// ─────────────────────────────────────────────────────────────────────────────
// src/components/modules/employees/Employees.jsx
// Employee directory with Add Employee modal (Admin/HR only)
// ─────────────────────────────────────────────────────────────────────────────

import { useState } from "react";
import { Icon, Modal } from "../../common";
import { DEPARTMENTS } from "../../../data/mockData";
import { avatarColor } from "../../../utils/helpers";

const EMPTY_FORM = { name: "", email: "", department: "Engineering", role: "employee", managerId: "" };

const Employees = ({ user, employees, addEmployee }) => {
  const [search, setSearch] = useState("");
  const [deptFilter, setDeptFilter] = useState("All");
  const [showAdd, setShowAdd] = useState(false);
  const [form, setForm] = useState(EMPTY_FORM);
  const [errors, setErrors] = useState({});
  const [success, setSuccess] = useState(false);

  const canManage = user?.role === "admin" || user?.role === "hr";

  const filtered = employees.filter(
    (e) =>
      (deptFilter === "All" || e.dept === deptFilter) &&
      e.name.toLowerCase().includes(search.toLowerCase())
  );

  const set = (key, val) => setForm((f) => ({ ...f, [key]: val }));

  const validate = () => {
    const e = {};
    if (!form.name.trim()) e.name = "Name is required";
    if (!form.email.trim()) e.email = "Email is required";
    else if (!/\S+@\S+\.\S+/.test(form.email)) e.email = "Invalid email format";
    else if (employees.find((emp) => emp.email === form.email)) e.email = "Email already exists";
    if (!form.department) e.department = "Department is required";
    setErrors(e);
    return Object.keys(e).length === 0;
  };

  const handleAdd = async () => {
    if (!validate()) return;
    try {
      await addEmployee(form);
      setSuccess(true);
      setShowAdd(false);
      setForm(EMPTY_FORM);
      setErrors({});
      setTimeout(() => setSuccess(false), 3000);
    } catch (err) {
      setErrors({ submit: err.message || "Failed to add employee" });
    }
  };

  return (
    <div className="fade-in">
      {/* Header */}
      <div style={{ display: "flex", alignItems: "center", justifyContent: "space-between", marginBottom: 24 }}>
        <div>
          <h1 style={{ fontFamily: "Syne", fontSize: 22, fontWeight: 800 }}>Employees</h1>
          <p style={{ color: "#6b7280", fontSize: 13, marginTop: 3 }}>Manage employee directory</p>
        </div>

        <div style={{ display: "flex", gap: 10 }}>
          <div style={{ position: "relative" }}>
            <Icon name="search" size={14} color="#9ca3af" style={{ position: "absolute", left: 10, top: "50%", transform: "translateY(-50%)" }} />
            <input className="form-input" placeholder="Search..." value={search} onChange={(e) => setSearch(e.target.value)} style={{ paddingLeft: 32, width: 200 }} />
          </div>
          <select className="form-input" value={deptFilter} onChange={(e) => setDeptFilter(e.target.value)} style={{ width: 160 }}>
            <option value="All">All Departments</option>
            {DEPARTMENTS.map((d) => <option key={d}>{d}</option>)}
          </select>
          {canManage && (
            <button className="btn btn-primary" onClick={() => setShowAdd(true)}>
              <Icon name="plus" size={15} color="#fff" /> Add Employee
            </button>
          )}
        </div>
      </div>

      {/* Success banner */}
      {success && (
        <div style={{ background: "#d1fae5", border: "1px solid #6ee7b7", borderRadius: 12, padding: "14px 18px", marginBottom: 20, display: "flex", alignItems: "center", gap: 10, color: "#065f46", fontSize: 14, fontWeight: 600 }}>
          <Icon name="check" size={18} color="#10b981" />
          Employee added successfully!
        </div>
      )}

      {/* Card grid */}
      <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fill, minmax(280px, 1fr))", gap: 16 }}>
        {filtered.map((emp) => (
          <div key={emp.id} className="card" style={{ padding: 20 }}>
            <div style={{ display: "flex", alignItems: "center", gap: 12, marginBottom: 14 }}>
              <div className="avatar" style={{ background: avatarColor(emp.id), width: 48, height: 48, fontSize: 16 }}>
                {emp.avatar}
              </div>
              <div>
                <div style={{ fontWeight: 700, fontSize: 15 }}>{emp.name}</div>
                <div style={{ fontSize: 12, color: "#9ca3af" }}>{emp.email}</div>
              </div>
            </div>
            <div style={{ display: "flex", gap: 8, flexWrap: "wrap" }}>
              <span className="tag" style={{ background: "#eef2ff", color: "#4f46e5" }}>{emp.dept}</span>
              <span className="tag" style={{
                background: emp.role === "admin" ? "#fef3c7" : emp.role === "hr" ? "#d1fae5" : "#f3f4f6",
                color: emp.role === "admin" ? "#92400e" : emp.role === "hr" ? "#065f46" : "#374151",
                textTransform: "capitalize",
              }}>
                {emp.role}
              </span>
            </div>
          </div>
        ))}
      </div>

      {/* Add Employee Modal */}
      {showAdd && (
        <Modal title="Add New Employee" onClose={() => { setShowAdd(false); setErrors({}); }}>
          <div className="form-group">
            <label className="form-label">Full Name *</label>
            <input className="form-input" placeholder="e.g. Rahul Verma" value={form.name} onChange={(e) => set("name", e.target.value)} />
            {errors.name && <div style={{ color: "#ef4444", fontSize: 12, marginTop: 4 }}>{errors.name}</div>}
          </div>

          <div className="form-group">
            <label className="form-label">Email *</label>
            <input className="form-input" type="email" placeholder="e.g. rahul@company.com" value={form.email} onChange={(e) => set("email", e.target.value)} />
            {errors.email && <div style={{ color: "#ef4444", fontSize: 12, marginTop: 4 }}>{errors.email}</div>}
          </div>

          <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 14 }}>
            <div className="form-group">
              <label className="form-label">Department *</label>
              <select className="form-input" value={form.department} onChange={(e) => set("department", e.target.value)}>
                {DEPARTMENTS.map((d) => <option key={d} value={d}>{d}</option>)}
              </select>
            </div>

            <div className="form-group">
              <label className="form-label">Role *</label>
              <select className="form-input" value={form.role} onChange={(e) => set("role", e.target.value)}>
                <option value="employee">Employee</option>
                <option value="hr">HR</option>
                <option value="admin">Admin</option>
              </select>
            </div>
          </div>

          <div className="form-group">
            <label className="form-label">Manager (optional)</label>
            <select className="form-input" value={form.managerId} onChange={(e) => set("managerId", e.target.value)}>
              <option value="">No Manager</option>
              {employees.filter((e) => e.role === "hr" || e.role === "admin").map((e) => (
                <option key={e.id} value={e.id}>{e.name} ({e.role})</option>
              ))}
            </select>
          </div>

          {errors.submit && <div style={{ color: "#ef4444", fontSize: 13, marginBottom: 10 }}>{errors.submit}</div>}

          <div style={{ display: "flex", gap: 10, marginTop: 8 }}>
            <button className="btn btn-primary" onClick={handleAdd}>
              <Icon name="check" size={15} color="#fff" /> Add Employee
            </button>
            <button className="btn btn-ghost" onClick={() => { setShowAdd(false); setErrors({}); }}>Cancel</button>
          </div>
        </Modal>
      )}
    </div>
  );
};

export default Employees;
